def search_terms(terms, corpus, topn=20):
    scores = []
    for i,t in enumerate(corpus):
        score = sum(1 for term in terms if term in t)
        if score>0:
            scores.append((score, i, t))
    scores.sort(reverse=True)
    return scores[:topn]

